import { create } from 'zustand'

const useSplitPaymentStore = create((set) => ({
    plans: [],
    totalAmount: 24000,
    activePlan: null,
    planSchedule: null,
    showInstallments: false,
    setActivePlan: (plan) => set((state) => ({
        activePlan: plan
    })),
    setPlanSchedule: (scheduleList) => set((state) => ({
        planSchedule: [...scheduleList]
    })),
    setTotalAmount: (amount) => set((state) => ({
        totalAmount: amount
    })),
    setShowInstallments: () => set((state) => ({
        showInstallments: totalAmount > 0 && activePlan
    }))
}))

export default useSplitPaymentStore
